/**
 * نظام تخزين ثلاثي الطبقات — يضمن عدم فقدان البيانات على Android حتى عند إغلاق التطبيق قهراً
 *
 * الطبقة 1: IndexedDB  — الأسرع، يدعم مئات الميغابايت
 * الطبقة 2: localStorage — نسخة احتياطية فورية (مع حذف الصور الكبيرة إذا لزم)
 * الطبقة 3: Capacitor Filesystem — ملف JSON في مجلد التطبيق الخاص (Android فقط، لا يُمسح أبداً)
 */
function createIndexedDBStorage(): PersistStorage<any> {
  const DB_NAME = 'gt-sararim-db';
  const STORE_NAME = 'state';
  let dbPromise: Promise<IDBDatabase> | null = null;

  function getDB(): Promise<IDBDatabase> {
    if (!dbPromise) {
      dbPromise = new Promise((resolve, reject) => {
        const req = indexedDB.open(DB_NAME, 1);
        req.onupgradeneeded = () => {
          req.result.createObjectStore(STORE_NAME);
        };
        req.onsuccess = () => {
          const db = req.result;
          // ← الإصلاح الجوهري: إعادة التهيئة عند إغلاق الاتصال من طرف Android
          db.onclose = () => { dbPromise = null; };
          db.onerror = () => { dbPromise = null; };
          resolve(db);
        };
        req.onerror = () => { dbPromise = null; reject(req.error); };
        req.onblocked = () => { dbPromise = null; reject(new Error('IndexedDB blocked')); };
      });
    }
    return dbPromise;
  }

  // الطبقة 3: Filesystem (Android) — يكتب/يقرأ ملف JSON في مجلد التطبيق الخاص
  async function fsWrite(name: string, json: string): Promise<void> {
    try {
      const { Capacitor } = await import('@capacitor/core');
      if (!Capacitor.isNativePlatform()) return;
      const { Filesystem, Directory, Encoding } = await import('@capacitor/filesystem');
      await Filesystem.writeFile({ path: `${name}.json`, data: json, directory: Directory.Data, encoding: Encoding.UTF8 });
    } catch { /* تجاهل أي خطأ */ }
  }

  async function fsRead(name: string): Promise<string | null> {
    try {
      const { Capacitor } = await import('@capacitor/core');
      if (!Capacitor.isNativePlatform()) return null;
      const { Filesystem, Directory, Encoding } = await import('@capacitor/filesystem');
      const r = await Filesystem.readFile({ path: `${name}.json`, directory: Directory.Data, encoding: Encoding.UTF8 });
      return typeof r.data === 'string' ? r.data : null;
    } catch { return null; }
  }

  return {
    getItem: async (name: string): Promise<StorageValue<any> | null> => {
      // الطبقة 1: IndexedDB
      try {
        const db = await getDB();
        const stored = await new Promise<any>((resolve) => {
          const tx = db.transaction(STORE_NAME, 'readonly');
          const req = tx.objectStore(STORE_NAME).get(name);
          req.onsuccess = () => resolve(req.result ?? null);
          req.onerror = () => resolve(null);
        });
        if (stored !== null) {
          return typeof stored === 'string' ? JSON.parse(stored) : stored;
        }
      } catch { dbPromise = null; }

      // الطبقة 2: localStorage
      try {
        const s = localStorage.getItem(name);
        if (s) return JSON.parse(s);
      } catch { /* تجاهل */ }

      // الطبقة 3: Filesystem (Android)
      try {
        const s = await fsRead(name);
        if (s) return JSON.parse(s);
      } catch { /* تجاهل */ }

      return null;
    },

    setItem: async (name: string, value: StorageValue<any>): Promise<void> => {
      const json = JSON.stringify(value);
      const incomingUsers: any[] | undefined = (value as any)?.state?.users;

      // الطبقة 1: IndexedDB — مع إعادة محاولة واحدة عند الفشل
      for (let attempt = 0; attempt < 2; attempt++) {
        try {
          const db = await getDB();

          // حماية من الكتابة الفارغة: إذا كانت الحالة الواردة بلا مستخدمين،
          // تحقق أن IDB لا يحمل بيانات أصلية قبل الكتابة فوقها
          if (Array.isArray(incomingUsers) && incomingUsers.length === 0) {
            const existing = await new Promise<any>((resolve) => {
              const rtx = db.transaction(STORE_NAME, 'readonly');
              const rreq = rtx.objectStore(STORE_NAME).get(name);
              rreq.onsuccess = () => resolve(rreq.result ?? null);
              rreq.onerror = () => resolve(null);
            });
            if (existing !== null) {
              try {
                const parsed = typeof existing === 'string' ? JSON.parse(existing) : existing;
                if (Array.isArray(parsed?.state?.users) && parsed.state.users.length > 0) {
                  break; // IDB يحتوي على مستخدمين — لا نكتب فوقهم بحالة فارغة
                }
              } catch { /* تجاهل خطأ التحليل */ }
            }
          }

          await new Promise<void>((resolve, reject) => {
            const tx = db.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).put(json, name);
            tx.oncomplete = () => resolve();
            tx.onerror = () => { dbPromise = null; reject(tx.error); };
            tx.onabort = () => { dbPromise = null; reject(new Error('Transaction aborted')); };
          });
          break; // نجح الحفظ
        } catch {
          dbPromise = null;
          // المحاولة الثانية تفتح اتصالاً جديداً تلقائياً
        }
      }

      // الطبقة 2: localStorage — دائماً، حتى إذا كانت البيانات كبيرة
      try {
        localStorage.setItem(name, json);
      } catch {
        // إذا امتلأ localStorage: احفظ نسخة بدون الصور الكبيرة (base64)
        try {
          const v = value as any;
          const trimmed = v?.state
            ? { ...v, state: { ...v.state, localImages: {} } }
            : v;
          localStorage.setItem(name, JSON.stringify(trimmed));
        } catch { /* تجاهل */ }
      }

      // الطبقة 3: Filesystem (Android) — مُنتظَرة لضمان الكتابة الكاملة قبل أي إيقاف مفاجئ
      await fsWrite(name, json);
    },

    removeItem: async (name: string): Promise<void> => {
      try {
        const db = await getDB();
        await new Promise<void>((resolve) => {
          const tx = db.transaction(STORE_NAME, 'readwrite');
          tx.objectStore(STORE_NAME).delete(name);
          tx.oncomplete = () => resolve();
          tx.onerror = () => resolve();
        });
      } catch { dbPromise = null; }
      try { localStorage.removeItem(name); } catch { /* تجاهل */ }
    },
  };
}

