// ======= STORE INTERFACE =======
interface StoreActions {
  setCurrentUser: (user: UserProfile | null) => void;
  addUser: (user: UserProfile) => void;
  updateUser: (id: string, updates: Partial<UserProfile>) => void;
  deleteUser: (id: string) => void;
  updateSettings: (updates: Partial<ParentSettings>) => void;
  addStory: (story: Story) => void;
  updateStory: (id: string, updates: Partial<Story>) => void;
  deleteStory: (id: string) => void;
  addQuestion: (q: Question) => void;
  updateQuestion: (id: string, updates: Partial<Question>) => void;
  deleteQuestion: (id: string) => void;
  addPuzzle: (p: Puzzle) => void;
  updatePuzzle: (id: string, updates: Partial<Puzzle>) => void;
  deletePuzzle: (id: string) => void;
  setTheme: (t: 'light' | 'dark') => void; // يغيّر الثيم فقط دون المساس بـ themeIsDefault
  toggleTheme: () => void;
  resetToDefault: (keepChildren?: boolean) => void;
  exportData: () => Promise<void>;
  shareBackupData: () => Promise<void>;
  importData: (data: any) => void;
  addLocalImage: (id: string, file: File) => Promise<string>;
  getLocalImage: (id: string) => string | null;
  deleteLocalImage: (id: string) => void;
  updateLevelProgress: (userId: string, levelId: Level, progress: Partial<LevelProgress>) => void;
  getCurrentLevel: (userId: string) => Level;
  addCustomSound: (name: string, file: File) => Promise<void>;
  deleteSound: (id: string) => void;
  restoreSound: (sound: BackgroundSound) => void;
  addFont: (id: string, name: string, dataUrl: string) => void;
  removeFont: (id: string) => void;
  addStoryCategory: (cat: Omit<StoryCategory, 'id'>) => void;
  updateStoryCategory: (id: string, updates: Partial<StoryCategory>) => void;
  deleteStoryCategory: (id: string) => void;
  scheduledDelete: (type: PendingDelete['type'], id: string, data: any) => string;
  cancelDelete: (pendingId: string) => void;
  commitPendingDeletes: () => void;
  addColoringImage: (img: CustomColoringImage) => void;
  deleteColoringImage: (id: string) => void;
}

export const useStore = create<AppState & StoreActions>()(
  persist(
    (set, get) => ({
      currentUser: null,
      users: [],
      stories: INITIAL_STORIES,
      questions: INITIAL_QUESTIONS,
      puzzles: INITIAL_PUZZLES,
      settings: DEFAULT_SETTINGS,
      progress: {},
      theme: 'light',
      themeIsDefault: true,
      localImages: {},
      levelProgress: {},
      backgroundSounds: BUILT_IN_SOUNDS,
      pendingDeletes: [],
      childrenBackup: [],
      customColoringImages: [],

      addLocalImage: async (id, file) => {
        const base64 = await fileToBase64(file);
        set(s => ({ localImages: { ...s.localImages, [id]: { id, data: base64, mimeType: file.type, fileName: file.name } } }));
        return base64;
      },
      getLocalImage: (id) => get().localImages[id]?.data || null,
      deleteLocalImage: (id) => set(s => { const { [id]: _, ...rest } = s.localImages; return { localImages: rest }; }),

      setCurrentUser: (user) => set({ currentUser: user }),
      addUser: (user) => set(s => ({ users: [...s.users, { points: 0, achievements: [], playTimeToday: 0, lastActive: new Date().toISOString(), role: 'child', ...user }] })),
      updateUser: (id, updates) => set(s => ({
        users: s.users.map(u => u.id === id ? { ...u, ...updates } : u),
        currentUser: s.currentUser?.id === id ? { ...s.currentUser, ...updates } : s.currentUser
      })),
      deleteUser: (id) => set(s => ({
        users: s.users.filter(u => u.id !== id),
        currentUser: s.currentUser?.id === id ? null : s.currentUser
      })),

      updateSettings: (updates) => set(s => ({ settings: { ...s.settings, ...updates } })),

      addStory: (story) => set(s => ({ stories: [...s.stories, story] })),
      updateStory: (id, updates) => set(s => ({ stories: s.stories.map(x => x.id === id ? { ...x, ...updates } : x) })),
      deleteStory: (id) => set(s => ({ stories: s.stories.filter(x => x.id !== id) })),

      addQuestion: (q) => set(s => ({ questions: [...s.questions, q] })),
      updateQuestion: (id, updates) => set(s => ({ questions: s.questions.map(x => x.id === id ? { ...x, ...updates } : x) })),
      deleteQuestion: (id) => set(s => ({ questions: s.questions.filter(x => x.id !== id) })),

      addPuzzle: (p) => set(s => ({ puzzles: [...s.puzzles, p] })),
      updatePuzzle: (id, updates) => set(s => ({ puzzles: s.puzzles.map(x => x.id === id ? { ...x, ...updates } : x) })),
      deletePuzzle: (id) => set(s => ({ puzzles: s.puzzles.filter(x => x.id !== id) })),

      setTheme: (t) => set({ theme: t }),
      toggleTheme: () => set(s => ({ theme: s.theme === 'light' ? 'dark' : 'light', themeIsDefault: false })),

      resetToDefault: (keepChildren = false) => {
        const state = get();
        const childrenBackup = keepChildren ? state.users.filter(u => u.role === 'child') : [];
        set({
          stories: INITIAL_STORIES, questions: INITIAL_QUESTIONS, puzzles: INITIAL_PUZZLES,
          settings: DEFAULT_SETTINGS, users: keepChildren ? childrenBackup : [],
          currentUser: null, progress: {}, localImages: {}, levelProgress: {},
          backgroundSounds: BUILT_IN_SOUNDS, pendingDeletes: [],
          childrenBackup: state.users.filter(u => u.role === 'child'),
          customColoringImages: [],
        });
      },

      exportData: async () => {
        const s = get();
        const payload = {
          users: s.users,
          stories: s.stories,
          questions: s.questions,
          puzzles: s.puzzles,
          settings: s.settings,
          progress: s.progress,
          levelProgress: s.levelProgress,
          backgroundSounds: s.backgroundSounds.filter(x => !x.isBuiltIn),
          childrenBackup: s.childrenBackup,
          localImages: s.localImages,
          customColoringImages: s.customColoringImages,
        };
        const json = JSON.stringify(payload, null, 2);
        const filename = `gt-sararim-backup-${new Date().toISOString().split('T')[0]}.json`;

        // Android / iOS native: حفظ مباشر عبر Capacitor Filesystem
        try {
          const { Capacitor } = await import('@capacitor/core');
          if (Capacitor.isNativePlatform()) {
            const { Filesystem, Directory, Encoding } = await import('@capacitor/filesystem');
            const result = await Filesystem.writeFile({
              path: `Download/${filename}`,
              data: json,
              directory: Directory.ExternalStorage,
              encoding: Encoding.UTF8,
              recursive: true,
            }).catch(async () => {
              // fallback: مجلد Documents الخاص بالتطبيق
              return Filesystem.writeFile({
                path: filename,
                data: json,
                directory: Directory.Documents,
                encoding: Encoding.UTF8,
              });
            });
            const savedPath = result?.uri || filename;
            alert(`✓ تَمَّ حِفْظُ النُّسْخَةِ الِاحْتِيَاطِيَّةِ\n${savedPath.split('/').pop() ?? filename}\nفِي مُجَلَّدِ التَّنْزِيلَاتِ`);
            return;
          }
        } catch { /* Filesystem غير متاح، نستمر بالطرق الأخرى */ }

        // Web Share API (محاولة مشاركة الملف)
        if (navigator.share) {
          try {
            const file = new File([json], filename, { type: 'application/json' });
            if (!navigator.canShare || navigator.canShare({ files: [file] })) {
              await navigator.share({ files: [file], title: filename });
              return;
            }
          } catch (e: any) {
            if (e?.name === 'AbortError') return; // المستخدم ألغى العملية
          }
        }

        // Desktop / fallback: anchor download
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 1000);
      },

      // مشاركة النسخة الاحتياطية عبر تطبيقات النظام (واتساب، بريد، درايف...)
      shareBackupData: async () => {
        const s = get();
        const payload = {
          users: s.users,
          stories: s.stories,
          questions: s.questions,
          puzzles: s.puzzles,
          settings: s.settings,
          progress: s.progress,
          levelProgress: s.levelProgress,
          backgroundSounds: s.backgroundSounds.filter(x => !x.isBuiltIn),
          childrenBackup: s.childrenBackup,
          localImages: s.localImages,
          customColoringImages: s.customColoringImages,
        };
        const json = JSON.stringify(payload, null, 2);
        const filename = `gt-sararim-backup-${new Date().toISOString().split('T')[0]}.json`;

        // على Android: حفظ الملف ثم مشاركته عبر Capacitor Share
        try {
          const { Capacitor } = await import('@capacitor/core');
          if (Capacitor.isNativePlatform()) {
            const { Filesystem, Directory, Encoding } = await import('@capacitor/filesystem');
            const { Share } = await import('@capacitor/share');
            await Filesystem.writeFile({ path: filename, data: json, directory: Directory.Cache, encoding: Encoding.UTF8 });
            const uri = await Filesystem.getUri({ path: filename, directory: Directory.Cache });
            await Share.share({ title: 'GT-SARARIM — نسخة احتياطية', url: uri.uri, dialogTitle: 'حفظ أو إرسال النسخة الاحتياطية' });
            return;
          }
        } catch (e: any) {
          if (e?.name === 'AbortError') return;
        }

        // على الويب: Web Share API مع ملف
        if (navigator.share) {
          try {
            const file = new File([json], filename, { type: 'application/json' });
            const canShareFile = !navigator.canShare || navigator.canShare({ files: [file] });
            if (canShareFile) {
              await navigator.share({ files: [file], title: 'GT-SARARIM — نسخة احتياطية' });
              return;
            }
            await navigator.share({ title: 'GT-SARARIM — نسخة احتياطية', text: json });
            return;
          } catch (e: any) {
            if (e?.name === 'AbortError') return;
          }
        }
        // Fallback على الحاسوب: تنزيل الملف مباشرة
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url; a.download = filename;
        document.body.appendChild(a); a.click();
        setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 1000);
      },

      importData: (data) => {
        try {
          // دمج ذكي للمحتوى: يحافظ دائماً على المحتوى الأصلي المضمّن في التطبيق
          // + يضيف/يحدّث محتوى النسخة الاحتياطية دون حذف أي شيء
          const mergeContent = <T extends { id: string }>(initial: T[], backup?: T[]): T[] => {
            const map = new Map(initial.map(item => [item.id, item]));
            // النسخة الاحتياطية تُحدّث العناصر الموجودة وتضيف العناصر الجديدة
            (backup || []).forEach(item => map.set(item.id, item));
            return Array.from(map.values());
          };

          set(s => ({
            ...(data.users        ? { users: data.users }               : {}),
            stories:   mergeContent(INITIAL_STORIES,   data.stories),
            questions: mergeContent(INITIAL_QUESTIONS, data.questions),
            puzzles:   mergeContent(INITIAL_PUZZLES,   data.puzzles),
            ...(data.settings ? {
              settings: (() => {
                const merged = { ...s.settings, ...data.settings };
                // دائماً استعادة الأسماء العربية الصحيحة للفئات المدمجة
                const builtinMap = new Map(DEFAULT_CATEGORIES.map(c => [c.id, c]));
                const backupCats: StoryCategory[] = data.settings.storyCategories || [];
                const customCats = backupCats.filter((c: StoryCategory) => !builtinMap.has(c.id));
                merged.storyCategories = [...DEFAULT_CATEGORIES, ...customCats];
                return merged;
              })()
            } : {}),
            ...(data.progress     ? { progress: data.progress }         : {}),
            ...(data.levelProgress? { levelProgress: data.levelProgress }: {}),
            ...(data.localImages  ? { localImages: { ...s.localImages, ...data.localImages } } : {}),
            ...(data.backgroundSounds ? {
              backgroundSounds: [
                ...s.backgroundSounds.filter(x => x.isBuiltIn),
                ...data.backgroundSounds.filter((x: any) => !x.isBuiltIn),
              ]
            } : {}),
            ...(data.customColoringImages ? { customColoringImages: data.customColoringImages } : {}),
          }));
        } catch { /* ignore */ }
      },

      addColoringImage: (img) => set(s => ({ customColoringImages: [...s.customColoringImages, img] })),
      deleteColoringImage: (id) => set(s => ({ customColoringImages: s.customColoringImages.filter(x => x.id !== id) })),

      updateLevelProgress: (userId, levelId, progress) => set(s => ({
        levelProgress: {
          ...s.levelProgress,
          [`${userId}_${levelId}`]: { levelId, completedStories: [], completedPuzzles: [], completedActivities: [], quizScore: 0, isCompleted: false, ...s.levelProgress[`${userId}_${levelId}`], ...progress }
        }
      })),

      getCurrentLevel: (userId) => {
        const user = get().users.find(u => u.id === userId);
        if (!user) return 'beginner';
        for (let i = LEVELS.length - 1; i >= 0; i--) {
          if (user.points >= LEVELS[i].requiredPoints) return LEVELS[i].id;
        }
        return 'beginner';
      },

      addCustomSound: async (name, file) => {
        const data = await fileToBase64(file);
        const id = `sound_custom_${Date.now()}`;
        set(s => ({ backgroundSounds: [...s.backgroundSounds, { id, name, isBuiltIn: false, audioData: data }] }));
      },

      deleteSound: (id) => set(s => ({ backgroundSounds: s.backgroundSounds.filter(x => x.id !== id) })),
      restoreSound: (sound) => set(s => ({ backgroundSounds: s.backgroundSounds.find(x => x.id === sound.id) ? s.backgroundSounds : [...s.backgroundSounds, sound] })),
      // Font stored as localImage entry (large binary safe), only id+name in fontSettings
      addFont: (id, name, dataUrl) => set(s => ({
        localImages: { ...s.localImages, [`font_${id}`]: { data: dataUrl, name } },
        settings: {
          ...s.settings,
          fontSettings: {
            ...s.settings.fontSettings,
            fontFamily: id,
            customFonts: [
              ...(s.settings.fontSettings.customFonts || []).filter(f => f.id !== id),
              { id, name, url: '' }   // url is intentionally empty — data in localImages
            ]
          }
        }
      })),
      removeFont: (id) => set(s => {
        const newFonts = (s.settings.fontSettings.customFonts || []).filter(f => f.id !== id);
        const newFamily = s.settings.fontSettings.fontFamily === id ? 'ubuntu-arabic' : s.settings.fontSettings.fontFamily;
        const { [`font_${id}`]: _, ...restImages } = s.localImages;
        return {
          localImages: restImages,
          settings: { ...s.settings, fontSettings: { ...s.settings.fontSettings, fontFamily: newFamily, customFonts: newFonts } }
        };
      }),

      addStoryCategory: (cat) => set(s => ({
        settings: { ...s.settings, storyCategories: [...s.settings.storyCategories, { ...cat, id: `cat_${Date.now()}` }] }
      })),
      updateStoryCategory: (id, updates) => set(s => ({
        settings: { ...s.settings, storyCategories: s.settings.storyCategories.map(c => c.id === id ? { ...c, ...updates } : c) }
      })),
      deleteStoryCategory: (id) => set(s => ({
        settings: { ...s.settings, storyCategories: s.settings.storyCategories.filter(c => c.id !== id) }
      })),

      scheduledDelete: (type, id, data) => {
        const pendingId = `pending_${Date.now()}`;
        const expiresAt = Date.now() + 10000; // 10 seconds
        set(s => ({ pendingDeletes: [...s.pendingDeletes, { id: pendingId, type, data: { ...data, originalId: id }, expiresAt }] }));
        // Auto-commit after 10s
        setTimeout(() => {
          const state = get();
          const pending = state.pendingDeletes.find(p => p.id === pendingId);
          if (pending) {
            get().commitPendingDeletes();
          }
        }, 10000);
        return pendingId;
      },

      cancelDelete: (pendingId) => set(s => ({ pendingDeletes: s.pendingDeletes.filter(p => p.id !== pendingId) })),

      commitPendingDeletes: () => {
        const state = get();
        const now = Date.now();
        const toDelete = state.pendingDeletes.filter(p => p.expiresAt <= now);
        toDelete.forEach(p => {
          const oid = p.data.originalId;
          if (p.type === 'story') get().deleteStory(oid);
          else if (p.type === 'question') get().deleteQuestion(oid);
          else if (p.type === 'puzzle') get().deletePuzzle(oid);
          else if (p.type === 'user') get().deleteUser(oid);
          else if (p.type === 'sound') get().deleteSound(oid);
          else if (p.type === 'category') get().deleteStoryCategory(oid);
        });
        set(s => ({ pendingDeletes: s.pendingDeletes.filter(p => p.expiresAt > now) }));
      },
    }),
    {
      name: 'gt-sararim-storage-v6',
      // استخدام IndexedDB بدلاً من localStorage لتجنب حد الـ 5MB وفقدان البيانات على Android
      storage: createIndexedDBStorage(),
      onRehydrateStorage: () => (state) => {
        if (!state) return;
        // دمج الأصوات المدمجة الجديدة وإزالة الأصوات المركبة القديمة
        const synthIds = new Set(['sound_stream','sound_rain','sound_nature','sound_calm']);
        const cleanedSounds = (state.backgroundSounds || []).filter((s: BackgroundSound) => !synthIds.has(s.id));
        const storedIds = new Set(cleanedSounds.map((s: BackgroundSound) => s.id));
        const missing = BUILT_IN_SOUNDS.filter(s => !storedIds.has(s.id));
        state.backgroundSounds = [...missing, ...cleanedSounds];
        // إضافة timeLimitEnabled إذا لم يكن موجوداً (بيانات قديمة)
        if (state.settings && state.settings.timeLimitEnabled === undefined) {
          state.settings.timeLimitEnabled = false;
        }
        // ترقية الخط الافتراضي من ubuntu-arabic إلى noto-arabic
        if (state.settings?.fontSettings?.fontFamily === 'ubuntu-arabic') {
          state.settings.fontSettings.fontFamily = 'noto-arabic';
        }
        // ضمان وجود جميع الفئات الافتراضية (ترقية البيانات القديمة)
        if (state.settings && Array.isArray(state.settings.storyCategories)) {
          const existingIds = new Set(state.settings.storyCategories.map((c: StoryCategory) => c.id));
          const missing = DEFAULT_CATEGORIES.filter(c => !existingIds.has(c.id));
          if (missing.length > 0) {
            state.settings.storyCategories = [...state.settings.storyCategories, ...missing];
          }
        }
        // اكتشاف ثيم النظام عند كل فتح إذا لم يختر المستخدم يدوياً
        if (state.themeIsDefault !== false) {
          state.themeIsDefault = true;
          const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
          state.theme = prefersDark ? 'dark' : 'light';
        }
        // دائماً يفتح التطبيق في شاشة الدخول
        state.currentUser = null;
      },
    }
  )
);
